// Create a gradient background using node-canvas
const { createCanvas } = require('canvas');

// Create canvas
const width = 800;
const height = 600;
const canvas = createCanvas(width, height);
const ctx = canvas.getContext('2d');

// Create linear gradient
const linearGradient = ctx.createLinearGradient(0, 0, width, height);
linearGradient.addColorStop(0, '#667eea');
linearGradient.addColorStop(0.5, '#764ba2');
linearGradient.addColorStop(1, '#f093fb');

// Fill with linear gradient
ctx.fillStyle = linearGradient;
ctx.fillRect(0, 0, width, height);

// Add radial gradient overlay
const radialGradient = ctx.createRadialGradient(width / 2, height / 2, 0, width / 2, height / 2, width / 2);
radialGradient.addColorStop(0, 'rgba(255, 255, 255, 0.3)');
radialGradient.addColorStop(1, 'rgba(0, 0, 0, 0.2)');

ctx.fillStyle = radialGradient;
ctx.fillRect(0, 0, width, height);

// Convert to PNG buffer
const buffer = canvas.toBuffer('image/png');

// Return as binary data
return [
  {
    json: {},
    binary: {
      data: {
        data: buffer.toString('base64'),
        mimeType: 'image/png',
        fileName: 'gradient-background.png'
      }
    }
  }
];

const { createCanvas } = require('canvas');

// Create a canvas
const width = 800;
const height = 600;
const canvas = createCanvas(width, height);
const ctx = canvas.getContext('2d');

// Fill background
ctx.fillStyle = '#f0f0f0';
ctx.fillRect(0, 0, width, height);

// Draw a circle
ctx.fillStyle = '#FF6B6B';
ctx.beginPath();
ctx.arc(200, 150, 80, 0, Math.PI * 2);
ctx.fill();

// Draw a rectangle
ctx.fillStyle = '#4ECDC4';
ctx.fillRect(350, 70, 160, 160);

// Draw a triangle
ctx.fillStyle = '#FFE66D';
ctx.beginPath();
ctx.moveTo(600, 230);
ctx.lineTo(700, 230);
ctx.lineTo(650, 130);
ctx.closePath();
ctx.fill();

// Draw a pentagon
ctx.fillStyle = '#95E1D3';
ctx.beginPath();
const sides = 5;
const radius = 70;
const centerX = 200;
const centerY = 400;
for (let i = 0; i < sides; i++) {
  const angle = (i * 2 * Math.PI) / sides - Math.PI / 2;
  const x = centerX + radius * Math.cos(angle);
  const y = centerY + radius * Math.sin(angle);
  if (i === 0) {
    ctx.moveTo(x, y);
  } else {
    ctx.lineTo(x, y);
  }
}
ctx.closePath();
ctx.fill();

// Draw a hexagon with pattern
ctx.fillStyle = '#A8E6CF';
ctx.beginPath();
const hexSides = 6;
const hexRadius = 80;
const hexCenterX = 450;
const hexCenterY = 400;
for (let i = 0; i < hexSides; i++) {
  const angle = (i * 2 * Math.PI) / hexSides;
  const x = hexCenterX + hexRadius * Math.cos(angle);
  const y = hexCenterY + hexRadius * Math.sin(angle);
  if (i === 0) {
    ctx.moveTo(x, y);
  } else {
    ctx.lineTo(x, y);
  }
}
ctx.closePath();
ctx.fill();

// Draw a star
ctx.fillStyle = '#FFD93D';
ctx.beginPath();
const spikes = 5;
const outerRadius = 60;
const innerRadius = 30;
const starCenterX = 650;
const starCenterY = 450;
for (let i = 0; i < spikes * 2; i++) {
  const radius = i % 2 === 0 ? outerRadius : innerRadius;
  const angle = (i * Math.PI) / spikes - Math.PI / 2;
  const x = starCenterX + radius * Math.cos(angle);
  const y = starCenterY + radius * Math.sin(angle);
  if (i === 0) {
    ctx.moveTo(x, y);
  } else {
    ctx.lineTo(x, y);
  }
}
ctx.closePath();
ctx.fill();

// Add some stroked shapes
ctx.strokeStyle = '#6C5CE7';
ctx.lineWidth = 4;
ctx.beginPath();
ctx.arc(100, 500, 40, 0, Math.PI * 2);
ctx.stroke();

// Convert canvas to buffer
const buffer = canvas.toBuffer('image/png');

// Return the image as binary data
return [{
  json: {
    fileName: 'geometric_shapes.png',
    mimeType: 'image/png'
  },
  binary: {
    data: {
      data: buffer.toString('base64'),
      mimeType: 'image/png',
      fileName: 'geometric_shapes.png'
    }
  }
}];

