const { createCanvas } = require('canvas');

// Get pattern type from input or default to 'dots'
const patternType = $input.first().json.body?.pattern || 'dots';
const width = $input.first().json.body?.width || 800;
const height = $input.first().json.body?.height || 600;
const primaryColor = $input.first().json.body?.primaryColor || '#3498db';
const secondaryColor = $input.first().json.body?.secondaryColor || '#ffffff';

// Create canvas
const canvas = createCanvas(width, height);
const ctx = canvas.getContext('2d');

// Fill background
ctx.fillStyle = secondaryColor;
ctx.fillRect(0, 0, width, height);

// Generate pattern based on type
switch(patternType) {
  case 'dots':
    // Dot pattern
    const dotSize = 20;
    const dotSpacing = 50;
    ctx.fillStyle = primaryColor;
    for(let x = dotSpacing/2; x < width; x += dotSpacing) {
      for(let y = dotSpacing/2; y < height; y += dotSpacing) {
        ctx.beginPath();
        ctx.arc(x, y, dotSize/2, 0, Math.PI * 2);
        ctx.fill();
      }
    }
    break;

  case 'stripes':
    // Vertical stripes
    const stripeWidth = 40;
    ctx.fillStyle = primaryColor;
    for(let x = 0; x < width; x += stripeWidth * 2) {
      ctx.fillRect(x, 0, stripeWidth, height);
    }
    break;

  case 'waves':
    // Wave pattern
    ctx.strokeStyle = primaryColor;
    ctx.lineWidth = 3;
    const amplitude = 30;
    const frequency = 0.02;
    const waveSpacing = 40;

    for(let offsetY = 0; offsetY < height; offsetY += waveSpacing) {
      ctx.beginPath();
      for(let x = 0; x < width; x++) {
        const y = offsetY + Math.sin(x * frequency) * amplitude;
        if(x === 0) {
          ctx.moveTo(x, y);
        } else {
          ctx.lineTo(x, y);
        }
      }
      ctx.stroke();
    }
    break;

  case 'checkerboard':
    // Checkerboard pattern
    const squareSize = 50;
    ctx.fillStyle = primaryColor;
    for(let x = 0; x < width; x += squareSize) {
      for(let y = 0; y < height; y += squareSize) {
        if((Math.floor(x/squareSize) + Math.floor(y/squareSize)) % 2 === 0) {
          ctx.fillRect(x, y, squareSize, squareSize);
        }
      }
    }
    break;

  default:
    // Default to dots
    const defaultDotSize = 20;
    const defaultDotSpacing = 50;
    ctx.fillStyle = primaryColor;
    for(let x = defaultDotSpacing/2; x < width; x += defaultDotSpacing) {
      for(let y = defaultDotSpacing/2; y < height; y += defaultDotSpacing) {
        ctx.beginPath();
        ctx.arc(x, y, defaultDotSize/2, 0, Math.PI * 2);
        ctx.fill();
      }
    }
}

// Convert canvas to buffer
const buffer = canvas.toBuffer('image/png');

// Return as binary data
return [
  {
    json: {
      patternType,
      width,
      height,
      primaryColor,
      secondaryColor
    },
    binary: {
      data: await this.helpers.prepareBinaryData(buffer, 'pattern.png', 'image/png')
    }
  }
];

const { createCanvas, loadImage } = require('canvas');
const https = require('https');
const http = require('http');

// Get input data
const items = $input.all();
const imageUrl = items[0].json.body?.imageUrl || $('Workflow Configuration2').first().json.sampleImageUrl;
const overlayText = items[0].json.body?.text || 'Overlay Text';

// Function to load image from URL
function loadImageFromUrl(url) {
  return new Promise((resolve, reject) => {
    const protocol = url.startsWith('https') ? https : http;
    protocol.get(url, (response) => {
      const chunks = [];
      response.on('data', (chunk) => chunks.push(chunk));
      response.on('end', () => {
        const buffer = Buffer.concat(chunks);
        loadImage(buffer).then(resolve).catch(reject);
      });
    }).on('error', reject);
  });
}

// Load and process image
const image = await loadImageFromUrl(imageUrl);

// Create canvas with same dimensions as image
const canvas = createCanvas(image.width, image.height);
const ctx = canvas.getContext('2d');

// Draw original image
ctx.drawImage(image, 0, 0);

// Add semi-transparent overlay rectangle
ctx.fillStyle = 'rgba(0, 0, 0, 0.3)';
ctx.fillRect(0, image.height - 150, image.width, 150);

// Add decorative shapes
ctx.fillStyle = 'rgba(255, 215, 0, 0.6)';
ctx.beginPath();
ctx.arc(100, 100, 50, 0, Math.PI * 2);
ctx.fill();

ctx.fillStyle = 'rgba(255, 105, 180, 0.6)';
ctx.fillRect(image.width - 150, 50, 100, 100);

// Add text overlay
ctx.fillStyle = '#FFFFFF';
ctx.font = 'bold 48px Arial';
ctx.textAlign = 'center';
ctx.shadowColor = 'rgba(0, 0, 0, 0.8)';
ctx.shadowBlur = 10;
ctx.shadowOffsetX = 2;
ctx.shadowOffsetY = 2;
ctx.fillText(overlayText, image.width / 2, image.height - 75);

// Convert canvas to buffer
const buffer = canvas.toBuffer('image/png');

// Return as binary data
return [{
  json: {
    fileName: 'image-overlay.png',
    mimeType: 'image/png'
  },
  binary: {
    data: {
      data: buffer.toString('base64'),
      mimeType: 'image/png',
