    }
  }
}];

const { createCanvas, loadImage } = require('canvas');

// Get input items
const items = $input.all();
const results = [];

for (const item of items) {
  try {
    // Configuration
    const pixelSize = 8; // Size of each "pixel" block
    const width = 800;
    const height = 600;

    // Create canvas
    const canvas = createCanvas(width, height);
    const ctx = canvas.getContext('2d');

    // Retro color palette (limited colors for pixel art effect)
    const retroPalette = [
      '#000000', '#FFFFFF', '#FF0000', '#00FF00', '#0000FF',
      '#FFFF00', '#FF00FF', '#00FFFF', '#FF8800', '#8800FF',
      '#00FF88', '#FF0088', '#88FF00', '#0088FF', '#888888'
    ];

    // Function to find closest color in palette
    function getClosestColor(r, g, b) {
      let minDistance = Infinity;
      let closestColor = retroPalette[0];

      for (const color of retroPalette) {
        const pr = parseInt(color.substr(1, 2), 16);
        const pg = parseInt(color.substr(3, 2), 16);
        const pb = parseInt(color.substr(5, 2), 16);

        const distance = Math.sqrt(
          Math.pow(r - pr, 2) + 
          Math.pow(g - pg, 2) + 
          Math.pow(b - pb, 2)
        );

        if (distance < minDistance) {
          minDistance = distance;
          closestColor = color;
        }
      }

      return closestColor;
    }

    // Check if input has image data
    if (item.binary && item.binary.data) {
      // Load the input image
      const imageBuffer = Buffer.from(item.binary.data.data, 'base64');
      const image = await loadImage(imageBuffer);

      // Draw image scaled down then pixelate
      const tempCanvas = createCanvas(Math.floor(width / pixelSize), Math.floor(height / pixelSize));
      const tempCtx = tempCanvas.getContext('2d');
      tempCtx.drawImage(image, 0, 0, tempCanvas.width, tempCanvas.height);

      // Get pixel data
      const imageData = tempCtx.getImageData(0, 0, tempCanvas.width, tempCanvas.height);
      const pixels = imageData.data;

      // Draw pixelated version with retro colors
      for (let y = 0; y < tempCanvas.height; y++) {
        for (let x = 0; x < tempCanvas.width; x++) {
          const i = (y * tempCanvas.width + x) * 4;
          const r = pixels[i];
          const g = pixels[i + 1];
          const b = pixels[i + 2];

          const color = getClosestColor(r, g, b);
          ctx.fillStyle = color;
          ctx.fillRect(x * pixelSize, y * pixelSize, pixelSize, pixelSize);
        }
      }
    } else {
      // Generate random pixel art pattern
      for (let y = 0; y < height; y += pixelSize) {
        for (let x = 0; x < width; x += pixelSize) {
          const color = retroPalette[Math.floor(Math.random() * retroPalette.length)];
          ctx.fillStyle = color;
          ctx.fillRect(x, y, pixelSize, pixelSize);
        }
      }
    }

    // Convert to PNG buffer
    const buffer = canvas.toBuffer('image/png');

    results.push({
      json: {
        success: true,
        width: width,
        height: height,
        pixelSize: pixelSize,
        format: 'png'
      },
      binary: {
        data: {
          data: buffer.toString('base64'),
          mimeType: 'image/png',
          fileName: 'pixel-art.png'
        }
      }
    });

  } catch (error) {
    results.push({
      json: {
        success: false,
        error: error.message
      }
    });
  }
}

return results;

const { createCanvas, loadImage } = require('canvas');

// Get input image URL or data
const inputItem = $input.first();
let imageUrl;

if (inputItem.json.body && inputItem.json.body.imageUrl) {
  imageUrl = inputItem.json.body.imageUrl;
} else if (inputItem.binary && inputItem.binary.data) {
  // If binary data exists, we'll need to handle it differently
  imageUrl = $('Workflow Configuration2').first().json.sampleImageUrl;
} else {
  imageUrl = $('Workflow Configuration2').first().json.sampleImageUrl;
}

// Load the image
const image = await loadImage(imageUrl);

// Create canvas with same dimensions
const canvas = createCanvas(image.width, image.height);
const ctx = canvas.getContext('2d');

// Draw original image
ctx.drawImage(image, 0, 0);

// Get image data for manipulation
const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
const data = imageData.data;

// Create a new Uint8ClampedArray to avoid read-only error
const newData = new Uint8ClampedArray(data.length);

// Apply watercolor effect - soften edges and add transparency
for (let i = 0; i < data.length; i += 4) {
  // Add slight color bleeding effect
  const randomOffset = Math.random() * 20 - 10;
  newData[i] = Math.min(255, Math.max(0, data[i] + randomOffset));     // R
  newData[i + 1] = Math.min(255, Math.max(0, data[i + 1] + randomOffset)); // G
  newData[i + 2] = Math.min(255, Math.max(0, data[i + 2] + randomOffset)); // B

  // Add transparency variation for watercolor effect
  newData[i + 3] = Math.min(255, data[i + 3] * (0.85 + Math.random() * 0.15)); // A
}

// Create new ImageData with modified data
const newImageData = new ImageData(newData, canvas.width, canvas.height);

// Put modified image data back
ctx.putImageData(newImageData, 0, 0);

// Apply blur for soft edges
ctx.globalAlpha = 0.7;
ctx.filter = 'blur(2px)';
ctx.drawImage(canvas, 0, 0);

// Add paper texture overlay
ctx.globalAlpha = 0.1;
ctx.fillStyle = '#ffffff';
for (let i = 0; i < 1000; i++) {
  const x = Math.random() * canvas.width;
  const y = Math.random() * canvas.height;
  const size = Math.random() * 3;
  ctx.fillRect(x, y, size, size);
}

// Convert to PNG buffer
const buffer = canvas.toBuffer('image/png');

// Return as binary data
return [
  {
    json: {
      success: true,
      effect: 'watercolor',
      width: canvas.width,
      height: canvas.height
    },
    binary: {
      data: {
        data: buffer.toString('base64'),
        mimeType: 'image/png',
        fileName: 'watercolor-effect.png'
      }
    }
  }
];

const { createCanvas } = require('canvas');

// Create canvas
const width = 800;
const height = 600;
const canvas = createCanvas(width, height);
const ctx = canvas.getContext('2d');

// Dark background
ctx.fillStyle = '#0a0a0a';
ctx.fillRect(0, 0, width, height);

// Get text from input or use default
const text = $input.first().json.body?.text || 'NEON GLOW';

// Set up neon text effect
ctx.font = 'bold 80px Arial';
ctx.textAlign = 'center';
ctx.textBaseline = 'middle';

// Create multiple glow layers
const glowColors = [
  { color: '#ff00ff', blur: 40 },
  { color: '#00ffff', blur: 30 },
  { color: '#ff00ff', blur: 20 },
  { color: '#ffffff', blur: 10 }
];

// Draw glow layers
glowColors.forEach(({ color, blur }) => {
  ctx.save(); // Save context state
  ctx.shadowColor = color;
  ctx.shadowBlur = blur;
  ctx.fillStyle = color;
  ctx.fillText(text, width / 2, height / 2);
  ctx.restore(); // Restore context state
});

// Draw bright core text
ctx.save();
ctx.shadowBlur = 5;
ctx.shadowColor = '#ffffff';
ctx.fillStyle = '#ffffff';
ctx.fillText(text, width / 2, height / 2);
ctx.restore();

// Add some neon shapes
ctx.save();
ctx.shadowBlur = 30;
ctx.shadowColor = '#00ff00';
ctx.strokeStyle = '#00ff00';
ctx.lineWidth = 3;
ctx.beginPath();
ctx.arc(150, 150, 50, 0, Math.PI * 2);
ctx.stroke();
ctx.restore();

ctx.save();
ctx.shadowColor = '#ff0080';
ctx.strokeStyle = '#ff0080';
ctx.lineWidth = 3;
ctx.beginPath();
ctx.arc(650, 450, 60, 0, Math.PI * 2);
ctx.stroke();
ctx.restore();

// Convert to PNG buffer
const buffer = canvas.toBuffer('image/png');

// Return as binary data
return [
  {
    json: {},
    binary: {
      data: buffer
    }
  }
];
